import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../services/authService';
import { getUnreadCount } from '../services/api';
import NotificationCenter from './NotificationCenter';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (user) {
      const fetchCount = async () => {
        try {
          const count = await getUnreadCount();
          setUnreadCount(count);
        } catch (error) {
          console.error('Failed to fetch unread count', error);
        }
      };

      fetchCount();
      const interval = setInterval(fetchCount, 10000);
      return () => clearInterval(interval);
    }
  }, [user]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="glass-nav sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20 items-center">
          <div className="flex items-center">
            <Link to="/" className="flex-shrink-0 flex items-center group">
              <div className="p-2 bg-gradient-to-br from-accent-indigo to-accent-violet rounded-xl shadow-lg shadow-accent-indigo/30 group-hover:scale-110 transition-transform duration-300">
                <svg className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <span className="ml-3 text-2xl font-bold text-gradient tracking-tight">DocHub</span>
            </Link>
            {user && (
              <div className="hidden md:ml-10 md:flex md:space-x-8">
                <Link to="/documents" className="text-slate-400 hover:text-white px-1 py-1 text-sm font-medium transition-all relative group">
                  Documents
                  <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-accent-indigo transition-all group-hover:w-full"></span>
                </Link>
                <Link to="/upload" className="text-slate-400 hover:text-white px-1 py-1 text-sm font-medium transition-all relative group">
                  Upload
                  <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-accent-indigo transition-all group-hover:w-full"></span>
                </Link>
                <Link to="/chat" className="text-slate-400 hover:text-white px-1 py-1 text-sm font-medium transition-all relative group">
                  Messages
                  <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-accent-indigo transition-all group-hover:w-full"></span>
                </Link>
                {user.roles?.some(r => r.name === 'ROLE_ADMIN') && (
                  <Link to="/admin" className="text-slate-400 hover:text-white px-1 py-1 text-sm font-medium transition-all relative group">
                    Admin
                    <span className="absolute bottom-0 left-0 w-0 h-0.5 bg-accent-indigo transition-all group-hover:w-full"></span>
                  </Link>
                )}
              </div>
            )}
          </div>
          <div className="flex items-center space-x-6">
            {user && (
              <div className="relative">
                <button 
                  onClick={() => setIsNotificationOpen(!isNotificationOpen)}
                  className="p-2.5 text-slate-400 hover:text-white hover:bg-white/5 rounded-full transition-all relative border border-transparent hover:border-white/10"
                >
                  <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" />
                  </svg>
                  {unreadCount > 0 && (
                    <span className="absolute top-1.5 right-1.5 block h-4 w-4 rounded-full bg-accent-indigo text-white text-[10px] font-bold flex items-center justify-center animate-pulse border-2 border-primary-950">
                      {unreadCount}
                    </span>
                  )}
                </button>
                <NotificationCenter isOpen={isNotificationOpen} onClose={() => setIsNotificationOpen(false)} />
              </div>
            )}
            {user ? (
              <div className="flex items-center space-x-4 pl-4 border-l border-white/10">
                <div className="flex items-center space-x-3">
                  <div className="h-9 w-9 rounded-xl bg-gradient-to-br from-accent-indigo/20 to-accent-violet/20 border border-accent-indigo/30 flex items-center justify-center text-accent-indigo font-bold shadow-inner">
                    {user.username.charAt(0).toUpperCase()}
                  </div>
                  <span className="text-sm font-semibold text-slate-200 hidden md:block">{user.username}</span>
                </div>
                <button onClick={handleLogout} className="text-xs font-bold text-slate-500 hover:text-red-400 transition-colors uppercase tracking-wider">
                  Logout
                </button>
              </div>
            ) : (
              <div className="flex items-center space-x-4">
                <Link to="/login" className="text-sm font-semibold text-slate-300 hover:text-white transition-colors">Sign in</Link>
                <Link to="/register" className="btn-premium py-2 px-5 text-sm">Join now</Link>
              </div>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
